cues with premium everyday wearability.", "seller_display_name": "After Dark Wardrobe", "seller_handle": "@after_dark_wardrobe", "price_cents": 16400, "hero_image_url": "https://images.unsplash.com/photo-1496747611176-843222e1e57c?auto=format&fit=crop&w=1200&q=80", "drop_label": "After Dark Wardrobe", "tag_list": ["night-out", "dress", "evening", "satin"], "sort_rank": 19, "available_count": 16, "total_count": 58}, {"slug": "velvet-hour-blazer", "title": "Velvet Hour Blazer", "tagline": "Soft structured blazer for dinner fits and late city plans.", "description": "Velvet Hour Blazer is built for after dark wardrobe styling, combining night-out, blazer, evening cues with premium everyday wearability.", "seller_display_name": "After Dark Wardrobe", "seller_handle": "@after_dark_wardrobe", "price_cents": 18800, "hero_image_url": "https://images.unsplash.com/photo-1507679799987-c73779587ccf?auto=format&fit=crop&w=1200&q=80", "drop_label": "After Dark Wardrobe", "tag_list": ["night-out", "blazer", "evening", "tailored"], "sort_rank": 18, "available_count": 17, "total_count": 68}, {"slug": "midnight-mesh-top", "title": "Midnight Mesh Top", "tagline": "Layered mesh top for nightlife styling and bold contrast.", "description": "Midnight Mesh Top is built for after dark wardrobe styling, combining night-out, top, mesh cues with premium everyday wearability.", "seller_display_name": "After Dark Wardrobe", "seller_handle": "@after_dark_wardrobe", "price_cents": 9200, "hero_image_url": "https://images.unsplash.com/photo-1496747611176-843222e1e57c?auto=format&fit=crop&w=1200&q=80", "drop_label": "After Dark Wardrobe", "tag_list": ["night-out", "top", "mesh", "layered"], "sort_rank": 17, "available_count": 18, "total_count": 78}, {"slug": "strobe-tailored-trousers", "title": "Strobe Tailored Trousers", "tagline": "Sharp evening trousers with fluid drape and long line.", "description": "Strobe Tailored Trousers is built for after dark wardrobe styling, combining night-out, trousers, tailored cues with premium everyday wearability.", "seller_display_name": "After Dark Wardrobe", "seller_handle": "@after_dark_wardrobe", "price_cents": 14800, "hero_image_url": "https://images.unsplash.com/photo-1507679799987-c73779587ccf?auto=format&fit=crop&w=1200&q=80", "drop_label": "After Dark Wardrobe", "tag_list": ["night-out", "trousers", "tailored", "evening"], "sort_rank": 16, "available_count": 19, "total_count": 88}, {"slug": "moonlight-cropped-shirt", "title": "Moonlight Cropped Shirt", "tagline": "Clean cropped shirt for night styling and modern silhouettes.", "description": "Moonlight Cropped Shirt is built for after dark wardrobe styling, combining night-out, shirt, cropped cues with premium everyday wearability.", "seller_display_name": "After Dark Wardrobe", "seller_handle": "@after_dark_wardrobe", "price_cents": 9800, "hero_image_url": "https://images.unsplash.com/photo-1496747611176-843222e1e57c?auto=format&fit=crop&w=1200&q=80", "drop_label": "After Dark Wardrobe", "tag_list": ["night-out", "shirt", "cropped", "minimal"], "sort_rank": 15, "available_count": 20, "total_count": 98}, {"slug": "plainform-rib-tee", "title": "Plainform Rib Tee", "tagline": "Minimal rib tee for quiet wardrobes and clean layering.", "description": "Plainform Rib Tee is built for core basics styling, combining basics, tee, minimal cues with premium everyday wearability.", "seller_display_name": "Core Basics", "seller_handle": "@core_basics", "price_cents": 5400, "hero_image_url": "https://images.unsplash.com/photo-1521572163474-6864f9cf17ab?auto=format&fit=crop&w=1200&q=80", "drop_label": "Core Basics", "tag_list": ["basics", "tee", "minimal", "rib"], "sort_rank": 14, "available_count": 21, "total_count": 63}, {"slug": "linea-cotton-poplin-shirt", "title": "Linea Cotton Poplin Shirt", "tagline": "Crisp essential shirt with clean line and daily polish.", "description": "Linea Cotton Poplin Shirt is built for core basics styling, combining basics, shirt, cotton cues with premium everyday wearability.", "seller_display_name": "Core Basics", "seller_handle": "@core_basics", "price_cents": 10200, "hero_image_url": "https://images.unsplash.com/photo-1507679799987-c73779587ccf?auto=format&fit=crop&w=1200&q=80", "drop_label": "Core Basics", "tag_list": ["basics", "shirt", "cotton", "minimal"], "sort_rank": 13, "available_count": 22, "total_count": 73}, {"slug": "frame-straight-jeans", "title": "Frame Straight Jeans", "tagline": "Minimal straight-leg denim for repeat everyday wear.", "description": "Frame Straight Jeans is built for core basics styling, combining basics, jeans, denim cues with premium everyday wearability.", "seller_display_name": "Core Basics", "seller_handle": "@core_basics", "price_cents": 11400, "hero_image_url": "https://images.unsplash.com/photo-1541099649105-f69ad21f3246?auto=format&fit=crop&w=1200&q=80", "drop_label": "Core Basics", "tag_list": ["basics", "jeans", "denim", "everyday"], "sort_rank": 12, "available_count": 23, "total_count": 83}, {"slug": "calm-knit-tank", "title": "Calm Knit Tank", "tagline": "Refined knit tank for layering and warm-weather ease.", "description": "Calm Knit Tank is built for core basics styling, combining basics, tank, knit cues with premium everyday wearability.", "seller_display_name": "Core Basics", "seller_handle": "@core_basics", "price_cents": 6800, "hero_image_url": "https://images.unsplash.com/photo-1496747611176-843222e1e57c?auto=format&fit=crop&w=1200&q=80", "drop_label": "Core Basics", "tag_list": ["basics", "tank", "knit", "minimal"], "sort_rank": 11, "available_count": 24, "total_count": 93}, {"slug": "quietline-jersey-skirt", "title": "Quietline Jersey Skirt", "tagline": "Soft jersey column skirt with understated movement.", "description": "Quietline Jersey Skirt is built for core basics styling, combining basics, skirt, jersey cues with premium everyday wearability.", "seller_display_name": "Core Basics", "seller_handle": "@core_basics", "price_cents": 8600, "hero_image_url": "https://images.unsplash.com/photo-1496747611176-843222e1e57c?auto=format&fit=crop&w=1200&q=80", "drop_label": "Core Basics", "tag_list": ["basics", "skirt", "jersey", "minimal"], "sort_rank": 10, "available_count": 25, "total_count": 103}]'::jsonb) as products_data(
    slug text,
    title text,
    tagline text,
    description text,
    seller_display_name text,
    seller_handle text,
    price_cents integer,
    hero_image_url text,
    drop_label text,
    tag_list text[],
    sort_rank integer,
    available_count integer,
    total_count integer
  )
), upserted_products as (
  insert into public.products (
    slug,
    title,
    tagline,
    description,
    seller_display_name,
    seller_handle,
    price_cents,
    currency_code,
    hero_image_url,
    sale_end_time,
    drop_label,
    tag_list,
    sort_rank
  )
  select
    slug,
    title,
    tagline,
    description,
    seller_display_name,
    seller_handle,
    price_cents,
    'USD',
    hero_image_url,
    null,
    drop_label,
    tag_list,
    sort_rank
  from clothing_products
  on conflict (slug) do update
  set
    title = excluded.title,
    tagline = excluded.tagline,
    description = excluded.description,
    seller_display_name = excluded.seller_display_name,
    seller_handle = excluded.seller_handle,
    price_cents = excluded.price_cents,
    currency_code = excluded.currency_code,
    hero_image_url = excluded.hero_image_url,
    sale_end_time = excluded.sale_end_time,
    drop_label = excluded.drop_label,
    tag_list = excluded.tag_list,
    sort_rank = excluded.sort_rank
  returning id, slug, hero_image_url
), deleted_media as (
  delete from public.product_media
  where product_id in (select id from upserted_products)
), inserted_media as (
  insert into public.product_media (
    product_id,
    media_url,
    media_type,
    position
  )
  select
    id,
    hero_image_url,
    'image',
    0
  from upserted_products
  returning product_id
)
insert into public.inventory (
  product_id,
  available_count,
  total_count
)
select
  upserted_products.id,
  clothing_products.available_count,
  clothing_products.total_count
from upserted_products
join clothing_products on clothing_products.slug = upserted_products.slug
on conflict (product_id) do update
set
  available_count = excluded.available_count,
  total_count = excluded.total_count,
  updated_at = timezone('utc', now());
